import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, GET, OPTIONS",
};

function generateOTP(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function normalizePhone(phone: string): string {
  let cleaned = phone.replace(/[^\d+]/g, "");
  if (cleaned.startsWith("07")) {
    cleaned = "+263" + cleaned.slice(1);
  } else if (cleaned.startsWith("263") && !cleaned.startsWith("+")) {
    cleaned = "+" + cleaned;
  }
  return cleaned;
}

function isValidZimbabwePhone(phone: string): boolean {
  const normalized = normalizePhone(phone);
  return /^\+263(71|73|77|78)\d{7}$/.test(normalized);
}

function msisdn(phone: string): string {
  return phone.startsWith("+") ? phone.slice(1) : phone;
}

// ---------------------------------------------------------------------------
// SMS PROBE — tries every known auth/format variant, logs all results
// ---------------------------------------------------------------------------
async function probeSmsProvider(
  apiKey: string,
  senderId: string,
  testPhone: string
): Promise<Record<string, { status: number; body: string }>> {
  const BASE = "https://sms.localhost.co.zw";
  const recipient = msisdn(normalizePhone(testPhone));
  const message = "ZimCommute probe test";
  const b64key = btoa(`${apiKey}:`);
  const b64keypass = btoa(`${apiKey}:password`);
  const results: Record<string, { status: number; body: string }> = {};

  async function probe(label: string, url: string, init: RequestInit) {
    try {
      const r = await fetch(url, init);
      const body = await r.text();
      console.log(`[PROBE] ${label} => HTTP ${r.status} | ${body}`);
      results[label] = { status: r.status, body };
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      console.log(`[PROBE] ${label} => ERROR: ${msg}`);
      results[label] = { status: 0, body: msg };
    }
  }

  // 1. GET root — discover available endpoints
  await probe("GET_root_v1", `${BASE}/api/v1/`, { method: "GET" });
  await probe("GET_root", `${BASE}/api/`, { method: "GET" });

  // 2. GET send endpoint with no auth — see what error reveals
  await probe("GET_send_noauth", `${BASE}/api/v1/sms/send`, { method: "GET" });

  // 3. Query-param variants
  await probe(
    "GET_send_qp_apiKey",
    `${BASE}/api/v1/sms/send?apiKey=${encodeURIComponent(apiKey)}&recipient=${recipient}&message=${encodeURIComponent(message)}&senderId=${encodeURIComponent(senderId)}`,
    { method: "GET" }
  );
  await probe(
    "POST_send_qp_apiKey",
    `${BASE}/api/v1/sms/send?apiKey=${encodeURIComponent(apiKey)}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );
  await probe(
    "POST_send_qp_api_key",
    `${BASE}/api/v1/sms/send?api_key=${encodeURIComponent(apiKey)}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );
  await probe(
    "POST_send_qp_token",
    `${BASE}/api/v1/sms/send?token=${encodeURIComponent(apiKey)}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );
  await probe(
    "POST_send_qp_key",
    `${BASE}/api/v1/sms/send?key=${encodeURIComponent(apiKey)}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 4. Basic auth: api_key as username, empty password
  await probe(
    "POST_send_basic_key_empty",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Basic ${b64key}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 5. Basic auth: api_key as username, "password" as password
  await probe(
    "POST_send_basic_key_password",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Basic ${b64keypass}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 6. Bearer token
  await probe(
    "POST_send_bearer",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 7. Token header (Django REST Framework style)
  await probe(
    "POST_send_token",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Token ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 8. Api-Key header
  await probe(
    "POST_send_ApiKey_header",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Api-Key ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 9. X-API-Key header
  await probe(
    "POST_send_X-API-Key_header",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-API-Key": apiKey,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  // 10. api_key in JSON body
  await probe(
    "POST_send_body_apiKey",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ apiKey, recipient, message, senderId }),
    }
  );
  await probe(
    "POST_send_body_api_key",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ api_key: apiKey, recipient, message, senderId }),
    }
  );
  await probe(
    "POST_send_body_token",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ token: apiKey, recipient, message, senderId }),
    }
  );

  // 11. Form-encoded with api_key in body
  await probe(
    "POST_send_form_apiKey",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({ apiKey, recipient, message, senderId }).toString(),
    }
  );
  await probe(
    "POST_send_form_api_key",
    `${BASE}/api/v1/sms/send`,
    {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({ api_key: apiKey, recipient, message, senderId }).toString(),
    }
  );

  // 12. Try alternate URL paths
  await probe(
    "POST_v1_messages",
    `${BASE}/api/v1/messages/`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Token ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );
  await probe(
    "POST_v1_outbox",
    `${BASE}/api/v1/outbox/`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Token ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    }
  );

  return results;
}

// ---------------------------------------------------------------------------
// Determine the best working auth format from probe results and send real SMS
// ---------------------------------------------------------------------------
async function sendSMS(
  supabase: ReturnType<typeof createClient>,
  phoneNumber: string,
  message: string
): Promise<{ success: boolean; status: string; error?: string }> {
  const { data: config, error: configError } = await supabase
    .from("sms_config")
    .select("*")
    .eq("id", "sms_config_singleton")
    .single();

  if (configError || !config) {
    console.error("[SMS] Failed to load SMS config:", configError);
    return { success: false, status: "config_error", error: "SMS configuration not found" };
  }

  if (!config.enabled) {
    console.log("[SMS] SMS service is disabled");
    return { success: true, status: "disabled" };
  }

  if (config.test_mode) {
    console.log("[SMS] TEST MODE - OTP for", phoneNumber, ":", message);
    return { success: true, status: "test_mode" };
  }

  const apiUrl: string = config.api_url;
  const apiKey: string = config.api_key;
  const senderId: string = config.sender_id || "ZimCommute";
  const recipient = msisdn(phoneNumber);

  console.log("[SMS] Sending to", phoneNumber, "via", apiUrl);

  // Run probe first to find working auth, log everything
  console.log("[SMS] Running auth probe before send...");
  const probeResults = await probeSmsProvider(apiKey, senderId, phoneNumber);

  // Find first non-401 result from the probe
  const winner = Object.entries(probeResults).find(
    ([, v]) => v.status !== 0 && v.status !== 401 && v.status !== 403
  );

  if (winner) {
    console.log(`[SMS] Probe winner: ${winner[0]} => HTTP ${winner[1].status} | ${winner[1].body}`);
    // If the winner was a send attempt (not just a discovery GET) and returned 2xx, we're done
    if (winner[1].status >= 200 && winner[1].status < 300 && !winner[0].startsWith("GET_root") && !winner[0].startsWith("GET_send_noauth")) {
      return { success: true, status: "sent" };
    }
  } else {
    console.log("[SMS] All probe attempts returned 401/403/error. Falling back to Token auth.");
  }

  // Fallback: try Token auth (current behaviour)
  try {
    const res = await fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Token ${apiKey}`,
      },
      body: JSON.stringify({ recipient, message, senderId }),
    });

    const bodyText = await res.text();
    console.log(`[SMS] Fallback HTTP ${res.status} | Body: ${bodyText}`);

    if (!res.ok) {
      return { success: false, status: "provider_error", error: `HTTP ${res.status}: ${bodyText}` };
    }

    return { success: true, status: "sent" };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.error("[SMS] Request failed:", msg);
    return { success: false, status: "network_error", error: msg };
  }
}

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  const url = new URL(req.url);
  const path = url.pathname.replace(/^\/otp/, "");

  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

  // ---------------------------------------------------------------------------
  // GET /otp/probe — run the full probe and return results as JSON
  // ---------------------------------------------------------------------------
  if (path === "/probe" && req.method === "GET") {
    const { data: config } = await supabase
      .from("sms_config")
      .select("api_key, sender_id")
      .eq("id", "sms_config_singleton")
      .single();

    const testPhone = url.searchParams.get("phone") || "+263771234567";
    const results = await probeSmsProvider(
      config?.api_key ?? "",
      config?.sender_id ?? "ZimCommute",
      testPhone
    );

    // Summarise: which ones were NOT 401
    const nonAuth = Object.entries(results)
      .filter(([, v]) => v.status !== 401 && v.status !== 403 && v.status !== 0)
      .map(([k, v]) => ({ label: k, status: v.status, body: v.body }));

    return new Response(
      JSON.stringify({ all: results, nonAuthResults: nonAuth }, null, 2),
      { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }

  try {
    const body = await req.json();

    // POST /otp/send or /otp/resend
    if ((path === "/send" || path === "/resend") && req.method === "POST") {
      const { phoneNumber } = body;

      if (!phoneNumber) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number is required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      if (!isValidZimbabwePhone(normalizedPhone)) {
        return new Response(
          JSON.stringify({ success: false, message: "Please enter a valid Zimbabwe phone number" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // Rate limiting: max 3 OTPs per hour per phone
      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
      const { count } = await supabase
        .from("otp_verifications")
        .select("*", { count: "exact", head: true })
        .eq("phone_number", normalizedPhone)
        .gte("created_at", oneHourAgo);

      if ((count ?? 0) >= 3) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many OTP requests. Please wait 1 hour before trying again." }),
          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const otp = generateOTP();
      const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();

      await supabase
        .from("otp_verifications")
        .delete()
        .eq("phone_number", normalizedPhone)
        .eq("verified", false);

      const { error: insertError } = await supabase
        .from("otp_verifications")
        .insert({
          phone_number: normalizedPhone,
          otp,
          expires_at: expiresAt,
          verified: false,
          attempts: 0,
        });

      if (insertError) {
        console.error("[OTP] Failed to store OTP:", insertError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to generate OTP. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      console.log("[OTP] Generated for", normalizedPhone);

      const smsMessage = `Your ZimCommute verification code is: ${otp}. Valid for 5 minutes. Do not share this code.`;
      const smsResult = await sendSMS(supabase, normalizedPhone, smsMessage);

      if (!smsResult.success) {
        console.error("[OTP] SMS delivery failed:", smsResult.status, smsResult.error);
        return new Response(
          JSON.stringify({
            success: false,
            message: `SMS failed: ${smsResult.error}`,
            smsStatus: smsResult.status,
            smsError: smsResult.error,
          }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      return new Response(
        JSON.stringify({
          success: true,
          message: "OTP sent successfully",
          expiresIn: 300,
          smsStatus: smsResult.status,
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // POST /otp/verify
    if (path === "/verify" && req.method === "POST") {
      const { phoneNumber, otp } = body;

      if (!phoneNumber || !otp) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number and OTP are required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      const { data: otpRecord, error: otpError } = await supabase
        .from("otp_verifications")
        .select("*")
        .eq("phone_number", normalizedPhone)
        .eq("verified", false)
        .order("created_at", { ascending: false })
        .limit(1)
        .single();

      if (otpError || !otpRecord) {
        return new Response(
          JSON.stringify({ success: false, message: "No pending OTP found. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (new Date(otpRecord.expires_at) < new Date()) {
        return new Response(
          JSON.stringify({ success: false, message: "OTP has expired. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (otpRecord.attempts >= 5) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many failed attempts. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ attempts: otpRecord.attempts + 1 })
        .eq("id", otpRecord.id);

      if (otpRecord.otp !== otp.toString()) {
        const remaining = 5 - (otpRecord.attempts + 1);
        return new Response(
          JSON.stringify({
            success: false,
            message: `Invalid code. ${remaining > 0 ? `${remaining} attempts remaining.` : "Please request a new code."}`,
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ verified: true })
        .eq("id", otpRecord.id);

      const { data: user, error: userError } = await supabase
        .from("users")
        .upsert(
          { phone_number: normalizedPhone, updated_at: new Date().toISOString() },
          { onConflict: "phone_number", ignoreDuplicates: false }
        )
        .select()
        .single();

      if (userError || !user) {
        console.error("[OTP] Failed to upsert user:", userError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to create user account. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const token = `user_${user.id}`;
      console.log("[OTP] Verified for", normalizedPhone, "user:", user.id);

      return new Response(
        JSON.stringify({
          success: true,
          token,
          user: {
            id: user.id,
            phoneNumber: user.phone_number,
            fullName: user.full_name,
            email: user.email,
            profilePhotoUrl: user.profile_photo_url,
            userType: user.user_type,
            homeCity: user.home_city,
            verificationLevel: user.verification_level,
            role: user.role,
            walletBalance: user.wallet_balance,
            isBanned: user.is_banned,
            banReason: user.ban_reason,
            createdAt: user.created_at,
            updatedAt: user.updated_at,
          },
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(
      JSON.stringify({ success: false, message: "Not found" }),
      { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error("[OTP] Unhandled error:", errMsg);
    return new Response(
      JSON.stringify({ success: false, message: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

